+    min-height: 44px;
+    min-width: 44px;
     font-size: 13px;
     font-weight: 600;
     /* Prevent text wrapping */

@@ -121,16 +121,16 @@ html {

   /* Exception: view-mode segments are grouped controls - combined width provides touch target */
   .view-mode-segment {
