   .sequence-view__snap-btn,
   .sequence-view__frame-btn {
-    min-height: 32px !important;
-    min-width: 32px !important;
+    min-height: 44px !important;
+    min-width: 44px !important;
   }

   /* Larger checkbox/radio touch targets */
